@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
@Testcontainers
class WalkingSkeletonIntegrationTest : FunSpec() {
    @Autowired
    private lateinit var restTemplate: TestRestTemplate
    @Autowired
    private lateinit var dsl: DSLContext

    init {
        extension(SpringExtension())

        test("complete CQRS flow: API → Command → Event → Projection → Query") {
            // 1. POST /widgets → HTTP 201
            val createResponse = restTemplate.postForEntity(...)
            createResponse.statusCode shouldBe HttpStatus.CREATED

            // 2. Wait for projection (eventually, <10s)
            await.atMost(Duration.ofSeconds(10)).until {
                dsl.selectFrom(WIDGET_VIEW).where(...).fetchOne() != null
            }

            // 3. GET /widgets/:id → HTTP 200
            val getResponse = restTemplate.getForEntity(...)
            getResponse.statusCode shouldBe HttpStatus.OK
        }
    }
}
